int  active()
{
    int ret;
    FormDataSource fds = this;
    WHSWorkTemplateTable wHSWorkTemplateTable;

    ret = next active();

    wHSWorkTemplateTable = fds.formRun().dataSource(formDataSourceStr(WHSWorkTemplateTable, WHSWorkTemplateTable)).cursor();

    fds.object(fieldNum(WHSWorkTemplateTable, KPMGCommon_RearrangeProductionOrderLabel)).visible(false);
    if (wHSWorkTemplateTable.WorkTransType == WHSWorkTransType::Invent)
        fds.object(fieldNum(WHSWorkTemplateTable, KPMGCommon_RearrangeProductionOrderLabel)).visible(true);

    return ret;
}
